function SearchA() {
  const [keyword, setKeyword] = useState("");
  return <input value={keyword} onChange={(e) => setKeyword(e.target.value)} />;
}

function SearchB() {
  const [keyword, setKeyword] = useState("");   // 名字一樣，應該會同步吧??
  return <input value={keyword} onChange={(e) => setKeyword(e.target.value)} />;
}

function AddButton({ onAdd }) {
  return <button onClick={() => onAdd(10)}>+10</button>;
}

function Parent() {
  const [xp, setXp] = useState(0);
  return (
    <div>
      <AddButton onAdd={(n) => setXp(xp + n)} />
      <p>XP：{xp}</p>
    </div>
  );
}

